import{_ as e,o as t,c as r,a2 as o}from"./chunks/framework.ZhLefgN8.js";const _=JSON.parse('{"title":"送股与选股派息","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"stock-trading/corporate-actions/scrip-dividend.md","filePath":"zh-CN/stock-trading/corporate-actions/scrip-dividend.md"}'),i={name:"stock-trading/corporate-actions/scrip-dividend.md"};function d(n,a,p,s,c,l){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="送股与选股派息" tabindex="-1">送股与选股派息 <a class="header-anchor" href="#送股与选股派息" aria-label="Permalink to &quot;送股与选股派息&quot;">​</a></h1><p>送股定义、处理时间、选股选息参与条件及操作方式。</p><h2 id="什么是送股" tabindex="-1">什么是送股 <a class="header-anchor" href="#什么是送股" aria-label="Permalink to &quot;什么是送股&quot;">​</a></h2><p>送股也叫红股。在除权日前一天结算后，如果客户持有上市公司的股票，则都会参与送股。</p><p>除权日当天，上市公司的股票价格会下跌，所以股东会在开盘前看到自己的盈亏是亏损状态。这部分亏损的金额会变换成红股派送到股东的持仓中（持仓成本并不进行变动）。</p><p>送股后，股东的持仓由全部正股，变成了全部正股（价格下跌）+ 赠送的正股（价值为正股下跌的部分）。</p><h2 id="送股处理时间" tabindex="-1">送股处理时间 <a class="header-anchor" href="#送股处理时间" aria-label="Permalink to &quot;送股处理时间&quot;">​</a></h2><p>若客户符合送股要求，长桥会在派送日当天完成处理，将红股发放到账。送的红股与正股性质相同。</p><h2 id="什么是选股选息" tabindex="-1">什么是选股选息 <a class="header-anchor" href="#什么是选股选息" aria-label="Permalink to &quot;什么是选股选息&quot;">​</a></h2><p>选股选息是指上市公司向股东派发股息时，提供股票和现金两种分红选项，让股东进行二选一。</p><p>参与条件：在除权日前一天结算后，如果客户持有上市公司的股票，则拥有参与选股选息的资格。</p><h2 id="如何操作选股选息" tabindex="-1">如何操作选股选息 <a class="header-anchor" href="#如何操作选股选息" aria-label="Permalink to &quot;如何操作选股选息&quot;">​</a></h2><p>客户需要根据交易所公布的开始时间至截止日，在长桥 App - 资产 - 全部功能 - 选股选息 进行操作提交。</p><p>在选股选息的初期，因为各上市公司处理方式不同，有机会因上市公司尚未公布再投资价格而出现再投资价格为「待定」的状态。再投资价格的计算日期取决于上市公司公布的文件。</p>',14)])])}const u=e(i,[["render",d]]);export{_ as __pageData,u as default};
